from __future__ import annotations

import collections.abc as cabc
from contextlib import contextmanager
from gettext import gettext as _
import shutil

from ._compat import term_len
from .parser import _split_opt

# Can force a width.  This is used by the test system
FORCED_WIDTH: int | None = None


def measure_table(rows: cabc.Iterable[tuple[str, str]]) -> tuple[int, ...]:
    """
    Measure the display widths of each column in the given rows.

    Each row is an iterable of strings. The function returns a tuple where
    each element is the maximum width (in characters as reported by
    term_len) of that column across all rows.
    """
    widths: dict[int, int] = {}

    for row in rows:
        for idx, col in enumerate(row):
            widths[idx] = max(widths.get(idx, 0), term_len(col))

    return tuple(y for x, y in sorted(widths.items()))


def iter_rows(
    rows: cabc.Iterable[tuple[str, str]], col_count: int
) -> cabc.Iterator[tuple[str, ...]]:
    """
    Yield rows padded with empty strings up to col_count columns.

    This ensures every yielded row has exactly col_count elements.
    """
    for row in rows:
        yield row + ("",) * (col_count - len(row))


def wrap_text(
    text: str,
    width: int = 78,
    initial_indent: str = "",
    subsequent_indent: str = "",
    preserve_paragraphs: bool = False,
) -> str:
    """A helper function that intelligently wraps text.  By default, it
    assumes that it operates on a single paragraph of text but if the
    `preserve_paragraphs` parameter is provided it will intelligently
    handle paragraphs (defined by two empty lines).

    If paragraphs are handled, a paragraph can be prefixed with an empty
    line containing the ``\\b`` character (``\\x08``) to indicate that
    no rewrapping should happen in that block.

    :param text: the text that should be rewrapped.
    :param width: the maximum width for the text.
    :param initial_indent: the initial indent that should be placed on the
                           first line as a string.
    :param subsequent_indent: the indent string that should be placed on
                              each consecutive line.
    :param preserve_paragraphs: if this flag is set then the wrapping will
                                intelligently handle paragraphs.
    """
    from ._textwrap import TextWrapper

    text = text.expandtabs()
    wrapper = TextWrapper(
        width,
        initial_indent=initial_indent,
        subsequent_indent=subsequent_indent,
        replace_whitespace=False,
    )
    if not preserve_paragraphs:
        return wrapper.fill(text)

    p: list[tuple[int, bool, str]] = []
    buf: list[str] = []
    indent = None

    def _flush_par() -> None:
        """Flush the current paragraph buffer into the paragraph list.

        If the paragraph is prefixed with a bare "\b" line, it will be
        treated as raw (no rewrapping). Otherwise, lines are joined with
        spaces for rewrapping.
        """
        if not buf:
            return
        if buf[0].strip() == "\b":
            p.append((indent or 0, True, "\n".join(buf[1:])))
        else:
            p.append((indent or 0, False, " ".join(buf)))
        del buf[:]

    for line in text.splitlines():
        if not line:
            _flush_par()
            indent = None
        else:
            if indent is None:
                orig_len = term_len(line)
                line = line.lstrip()
                indent = orig_len - term_len(line)
            buf.append(line)
    _flush_par()

    rv = []
    for indent, raw, text in p:
        with wrapper.extra_indent(" " * indent):
            if raw:
                rv.append(wrapper.indent_only(text))
            else:
                rv.append(wrapper.fill(text))

    return "\n\n".join(rv)


class HelpFormatter:
    """This class helps with formatting text-based help pages.  It's
    usually just needed for very special internal cases, but it's also
    exposed so that developers can write their own fancy outputs.

    At present, it always writes into memory.

    :param indent_increment: the additional increment for each level.
    :param width: the width for the text.  This defaults to the terminal
                  width clamped to a maximum of 78.
    """

    def __init__(
        self,
        indent_increment: int = 2,
        width: int | None = None,
        max_width: int | None = None,
    ) -> None:
        """
        Initialize a HelpFormatter.

        :param indent_increment: number of spaces to add/remove when
                                 indenting/dedenting.
        :param width: Optional fixed width. If not provided, the terminal
                      width is used (and may be overridden by FORCED_WIDTH).
        :param max_width: Optional maximum width to clamp to.
        """
        self.indent_increment = indent_increment
        if max_width is None:
            max_width = 80
        if width is None:
            width = FORCED_WIDTH
            if width is None:
                # get terminal width fall back to 80
                try:
                    width = shutil.get_terminal_size().columns
                except Exception:
                    width = 80
        if max_width is not None:
            width = min(width, max_width)
        self.width = int(width)
        self.current_indent = 0
        self.buffer: list[str] = []

    def write(self, text: str) -> None:
        """Write raw text to the buffer without additional indentation."""
        self.buffer.append(text)

    def write_line(self, text: str = "") -> None:
        """Write a single line with the current indentation and a newline."""
        if text:
            self.buffer.append(" " * self.current_indent + text + "\n")
        else:
            self.buffer.append("\n")

    def write_paragraph(self) -> None:
        """Ensure there is a blank line separating paragraphs."""
        if not self.buffer:
            return
        if not self.buffer[-1].endswith("\n\n"):
            # If last ends with single newline, ensure two newlines.
            if self.buffer[-1].endswith("\n"):
                self.buffer.append("\n")
            else:
                self.buffer.append("\n\n")

    def write_text(self, text: str) -> None:
        """Write text as one or more wrapped paragraphs using the current indent."""
        text = text.strip("\n")
        if not text:
            self.write_line()
            return
        wrapped = wrap_text(
            text,
            width=self.width,
            initial_indent=" " * self.current_indent,
            subsequent_indent=" " * self.current_indent,
            preserve_paragraphs=True,
        )
        # Ensure a trailing newline
        self.buffer.append(wrapped + "\n")

    @contextmanager
    def indent(self, extra: int | None = None):
        """Context manager for temporarily increasing the indentation."""
        if extra is None:
            extra = self.indent_increment
        self.current_indent += extra
        try:
            yield
        finally:
            self.current_indent -= extra

    def write_dl(
        self,
        rows: cabc.Iterable[tuple[str, str]],
        col_max: int = 30,
        col_spacing: int = 2,
    ) -> None:
        """Write a definition list (rows of (term, description))."""
        rows_list = list(rows)
        if not rows_list:
            return

        col_count = max(len(r) for r in rows_list)
        widths = measure_table(rows_list)
        # ensure widths has at least one element
        if not widths:
            return

        first_col_width = widths[0]
        first_col_width = min(first_col_width, col_max)

        for row in iter_rows(rows_list, col_count):
            first = row[0]
            desc = row[1] if len(row) > 1 else ""
            if not desc:
                # No description, just write the first column.
                self.write_line(first)
                continue

            if term_len(first) <= first_col_width:
                # Put term and description on the same line, wrap description
                prefix = " " * self.current_indent + first.ljust(first_col_width) + " " * col_spacing
                subsequent = " " * (self.current_indent + first_col_width + col_spacing)
                wrapped = wrap_text(
                    desc,
                    width=self.width,
                    initial_indent=prefix,
                    subsequent_indent=subsequent,
                    preserve_paragraphs=True,
                )
                self.buffer.append(wrapped + "\n")
            else:
                # Term too long, write term on its own line and description indented.
                self.write_line(first)
                with self.indent(col_spacing):
                    wrapped = wrap_text(
                        desc,
                        width=self.width,
                        initial_indent=" " * self.current_indent,
                        subsequent_indent=" " * self.current_indent,
                        preserve_paragraphs=True,
                    )
                    self.buffer.append(wrapped + "\n")

    def getvalue(self) -> str:
        """Return the accumulated help text as a single string."""
        return "".join(self.buffer)

    def __str__(self) -> str:
        return self.getvalue()